                "auth_columns_insert_mysql" => "INSERT INTO _mtdt__tnt__trzzzioni__colonne(muac_editable, muac_validation_required, mc_id, actionid, muacview, ruoloid, utenteid, aziendaid) VALUES(@muac_editable, @muac_validation_required, @mc_id, @action_id, @muac_view, @ruolo_id, @utente_id, @azienda_id)",
                "auth_table_select_mysql" => "SELECT at.muat_id, at.md_id, at.actionid as action_id, at.muatdelete as muat_delete, at.muatedit as muat_edit, at.muatinsert as muat_insert, at.ruoloid as ruolo_id, at.utenteid as utente_id, at.muatview as muat_view, at.aziendaid as azienda_id, at.muatoverriderecordrestriction as muat_override_record_restriction, r.ruolo_des as ruolo_des, u.username as username FROM _mtdt__tnt__trzzzioni__tabelle at LEFT JOIN ruoli r ON r.id_ruolo = at.ruoloid LEFT JOIN utenti u ON u.id_utente = at.utenteid ",
                "auth_columns_select_mysql" => "SELECT ac.muac_id, ac.muac_editable, ac.muac_validation_required, ac.mc_id, ac.actionid as action_id, ac.muacview as muac_view, ac.ruoloid as ruolo_id, ac.utenteid as utente_id, ac.aziendaid as azienda_id, c.md_id, r.ruolo_des as ruolo_des, u.username as username FROM _mtdt__tnt__trzzzioni__colonne ac INNER JOIN _metadati__colonne c ON ac.mc_id = c.mc_id LEFT JOIN ruoli r ON r.id_ruolo = ac.ruoloid LEFT JOIN utenti u ON u.id_utente = ac.utenteid ",
                "auth_menu_select_mysql" => "SELECT mmid as  mm_id  ,muamid as  muam_id ,muamview as muam_view ,ruoloid as ruolo_id     ,utenteid as utente_id  FROM _mtdt__tnt__trizzazioni__menus ",
                "logged_users_select_mysql" => "SELECT id_utente as user_id, username, id_ruolo as role_id, isAdmin, id_azienda as azienda_id, IsLoggedIn as isLogged, ip, token as user_token, LastLoginDate, LastLogoutDate, LastActivityDate FROM utenti WHERE IsLoggedIn = 1",
                "stili_table_select_mysql" => "SELECT mdid as md_id    ,mustattributename  as must_attribute_name    ,mustattributevalue   as  must_attribute_value ,mustid  as must_id FROM _metadati__u_i__stili__tabelle ",
                "stili_table_insert_mysql" => "INSERT INTO _metadati__u_i__stili__tabelle(mdid,mustattributename,mustattributevalue) VALUES(@md_id, @must_attribute_name, @must_attribute_value) ",
                "stili_column_select_mysql" => "SELECT musc_id      ,musc_attribute_value_callback      ,musc_attribute_value      ,musc_attribute_name      ,_metadati__colonne.mc_id  FROM _metadati__u_i__stili__colonne INNER JOIN _metadati__colonne ON _metadati__u_i__stili__colonne.mc_id = _metadati__colonne.mc_id",
                "stili_column_insert_mysql" => "INSERT INTO _metadati__u_i__stili__colonne(musc_attribute_value_callback,musc_attribute_value,musc_attribute_name,mc_id) VALUES(@musc_attribute_value_callback, @musc_attribute_value, @musc_attribute_name, @mc_id) ",
